var boardThemenRes = $input.first().json;
var groupsRes = $('HTTP: DB Gruppen laden').first().json;

// Karte: Gruppen-ID → Confluence Space Key
var groupMap = {};
(groupsRes.results || []).forEach(function(r) {
  var sk = '';
  try { sk = r.properties['Confluence Space Key'].rich_text[0].plain_text; } catch(e) {}
  if (sk) groupMap[r.id] = sk;
});

// Alle BoardThemen mit Space Key aus der verlinkten Gruppe ermitteln
var allThemen = (boardThemenRes.results || []).map(function(entry) {
  var thema = '';
  try { thema = entry.properties.Thema.title[0].plain_text; } catch(e) {}

  var dateStr = '';
  try { dateStr = entry.properties['Termine-Datum'].rollup.array[0].date.start; } catch(e) {}
  var datum = '';
  if (dateStr) {
    var d = new Date(dateStr);
    datum = String(d.getDate()).padStart(2,'0') + '.' + String(d.getMonth()+1).padStart(2,'0') + '.' + d.getFullYear();
  }

  var vortragender = '';
  try { vortragender = entry.properties.Vortragender.rich_text[0].plain_text; } catch(e) {}
  var vortragUrl = '';
  try { vortragUrl = entry.properties['Vortrag URL'].url || ''; } catch(e) {}
  var summary = '';
  try { summary = entry.properties.Summary.rich_text[0].plain_text; } catch(e) {}

  // Space Key aus der verlinkten Gruppe lesen
  var spaceKey = '';
  try {
    var rels = entry.properties['DB Gruppen'].relation || [];
    if (rels.length > 0) spaceKey = groupMap[rels[0].id] || '';
  } catch(e) {}

  return { thema: thema, datum: datum, vortragender: vortragender,
           vortragUrl: vortragUrl, summary: summary, spaceKey: spaceKey };
});

// Nur Themen mit bekanntem Space Key
var withKey = allThemen.filter(function(t) { return t.spaceKey; });
if (withKey.length === 0) throw new Error('Keine BoardThemen mit verlinkter DB-Gruppe und Confluence Space Key gefunden');

// Häufigsten Space Key bestimmen (primärer Space für diesen Lauf)
var counts = {};
withKey.forEach(function(t) { counts[t.spaceKey] = (counts[t.spaceKey] || 0) + 1; });
var primarySpaceKey = '';
var maxCount = 0;
Object.keys(counts).forEach(function(sk) {
  if (counts[sk] > maxCount) { maxCount = counts[sk]; primarySpaceKey = sk; }
});

// Nur Themen des ermittelten Space Key behalten
var themen = withKey.filter(function(t) { return t.spaceKey === primarySpaceKey; });

// Sortieren: neueste zuerst
themen.sort(function(a, b) {
  if (!a.datum && !b.datum) return 0;
  if (!a.datum) return 1;
  if (!b.datum) return -1;
  return b.datum.split('.').reverse().join('-').localeCompare(a.datum.split('.').reverse().join('-'));
});

return [{ json: { themen: themen, count: themen.length, spaceKey: primarySpaceKey } }];

function esc(s) {
  return (s || '').replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');
}

function findMatchingTableEnd(str, tableStart) {
  var depth = 0;
  var pos = tableStart;
  while (pos < str.length) {
    var nextOpen = str.indexOf('<table', pos);
    var nextClose = str.indexOf('</table>', pos);
    if (nextClose === -1) return -1;
    if (nextOpen !== -1 && nextOpen < nextClose) { depth++; pos = nextOpen + 6; }
    else { if (depth === 0) return nextClose; depth--; pos = nextClose + 8; }
  }
  return -1;
}

function stripHtml(html) {
  return (html || '').replace(/<[^>]+>/g, '').replace(/&amp;/g,'&').replace(/&lt;/g,'<').replace(/&gt;/g,'>').trim();
}

// Themen aus dem aktualisierten Node
var themenSource;
try { themenSource = $('Code: Themen aktualisieren').first().json.themen; } catch(e) {}
if (!themenSource) themenSource = $('Code: Filtern & Transformieren').first().json.themen || [];

var res = $input.first().json;
var page = res.homepage || (res.results && res.results[0]);
if (!page) throw new Error('Confluence-Seite nicht gefunden');
var pageId = page.id;
var version = page.version.number;
var body = page.body.storage.value;
var bodyLower = body.toLowerCase();

// ── Bestehende Tabellenzeilen extrahieren ──────────────────────────────────
// Suche den Abschnitt "Themen - Vorträge" und die dazugehörige Tabelle
var searchCandidates = [
  'vorträge','vortr&auml;ge','vortr&#228;ge','vortr&#xe4;ge','vortr&#xE4;ge',
  'vortrage','themen - vortr','themen &ndash; vortr','themen / vortr','vortr'
];
var hi = -1;
for (var i = 0; i < searchCandidates.length; i++) {
  var idx = bodyLower.indexOf(searchCandidates[i]);
  if (idx !== -1) { hi = idx; break; }
}

var existingRowMap = {};  // thema_text_lowercase → vollständiges <tr>...</tr> HTML

if (hi !== -1) {
  var after = body.substring(hi);
  var ts = after.indexOf('<table');
  if (ts !== -1) {
    var te = findMatchingTableEnd(after, ts);
    if (te !== -1) {
      var tableHtml = after.substring(ts, te + 8);
      // Alle <tr> Elemente parsen (erste Zeile = Header, überspringen)
      var trPos = 0;
      var firstTr = tableHtml.indexOf('<tr', trPos);
      if (firstTr !== -1) {
        var firstTrEnd = tableHtml.indexOf('</tr>', firstTr) + 5;
        trPos = firstTrEnd;  // Header übersprungen
        while (trPos < tableHtml.length) {
          var trStart = tableHtml.indexOf('<tr', trPos);
          if (trStart === -1) break;
          var trEnd = tableHtml.indexOf('</tr>', trStart) + 5;
          var rowHtml = tableHtml.substring(trStart, trEnd);
          // Erste <td> = Thema-Zelle, Text extrahieren
          var tdStart = rowHtml.indexOf('<td');
          if (tdStart !== -1) {
            var tdEnd = rowHtml.indexOf('</td>', tdStart) + 5;
            var tdHtml = rowHtml.substring(tdStart, tdEnd);
            var themaText = stripHtml(tdHtml).toLowerCase();
            if (themaText) existingRowMap[themaText] = rowHtml;
          }
          trPos = trEnd;
        }
      }
    }
  }
}

// ── Neue Tabelle aufbauen ──────────────────────────────────────────────────
var header = '<tr>' +
  '<th><p><strong>Thema</strong></p></th>' +
  '<th><p><strong>Summary</strong></p></th>' +
  '<th><p><strong>Datum</strong></p></th>' +
  '<th><p><strong>Vortragender</strong></p></th>' +
  '</tr>';

var rows;
if (themenSource.length > 0) {
  rows = themenSource.map(function(t) {
    var themaKey = (t.thema || '').toLowerCase();
    // Bestehende Zeile vorhanden? → unverändert übernehmen (manuelle Links bleiben)
    if (existingRowMap[themaKey]) {
      return existingRowMap[themaKey];
    }
    // Neue Zeile: Link aus Workflow falls vorhanden, sonst plain Text
    var themaCell = t.confluenceFileUrl
      ? '<a href="' + t.confluenceFileUrl + '">' + esc(t.thema) + '</a>'
      : esc(t.thema);
    return '<tr>' +
      '<td><p>' + themaCell + '</p></td>' +
      '<td><p>' + esc(t.summary || '') + '</p></td>' +
      '<td><p>' + (t.datum || '') + '</p></td>' +
      '<td><p>' + esc(t.vortragender) + '</p></td>' +
      '</tr>';
  }).join('');
} else {
  rows = '<tr><td colspan="4"><p>Keine Themen vorhanden</p></td></tr>';
}

var newTable = '<table data-table-width="760" data-layout="default">' +
  '<colgroup><col/><col/><col/><col/></colgroup>' +
  '<tbody>' + header + rows + '</tbody>' +
  '</table>';

// ── Tabelle im Body ersetzen ──────────────────────────────────────────────
var newBody;
if (hi === -1) throw new Error('Abschnitt Vortraege nicht gefunden');

var afterSection = body.substring(hi);
var strategy = '';

var RICH_OPEN = '<ac:rich-text-body>';
var RICH_CLOSE = '</ac:rich-text-body>';
var rbStart = afterSection.indexOf(RICH_OPEN);
var rbClose = afterSection.indexOf(RICH_CLOSE);

if (rbStart !== -1 && rbClose !== -1 && rbStart < rbClose) {
  strategy = 'expand-macro';
  newBody = body.substring(0, hi + rbStart + RICH_OPEN.length) + newTable + body.substring(hi + rbClose);
} else {
  var headingClosePos = -1; var headingCloseTagLen = 0;
  for (var level = 1; level <= 6; level++) {
    var htag = '</h' + level + '>';
    var hpos = afterSection.indexOf(htag);
    if (hpos !== -1 && (headingClosePos === -1 || hpos < headingClosePos)) {
      headingClosePos = hpos; headingCloseTagLen = htag.length;
    }
  }
  var insertPoint = headingClosePos !== -1 ? headingClosePos + headingCloseTagLen : 0;
  var afterHeading = afterSection.substring(insertPoint);
  var tableInCell = afterHeading.indexOf('<table');
  if (tableInCell !== -1) {
    strategy = 'replace-existing-table';
    var tableEnd = findMatchingTableEnd(afterHeading, tableInCell);
    if (tableEnd === -1) throw new Error('Kein passendes </table>');
    newBody = body.substring(0, hi + insertPoint + tableInCell) + newTable + afterHeading.substring(tableEnd + 8);
  } else {
    strategy = 'insert-after-heading';
    newBody = body.substring(0, hi + insertPoint) + newTable + body.substring(hi + insertPoint);
  }
}

return [{ json: { pageId: pageId, version: version, newBody: newBody,
  debug: { strategy: strategy, themenCount: themenSource.length,
           existingRowsFound: Object.keys(existingRowMap).length,
           existingKeys: Object.keys(existingRowMap) } } }];

var confluenceRes = $input.first().json;
var themen = $('Code: Filtern & Transformieren').first().json.themen || [];

// Vortraege-Seite unter Dokumentenportal finden
var pages = confluenceRes.results || [];
var vortragPageId = '';
for (var i = 0; i < pages.length; i++) {
  var ancestors = pages[i].ancestors || [];
  var underDokPortal = ancestors.some(function(a) {
    return (a.title || '').toLowerCase().indexOf('dokumentenportal') !== -1;
  });
  if (underDokPortal || pages.length === 1) { vortragPageId = pages[i].id; break; }
}
if (!vortragPageId && pages.length > 0) vortragPageId = pages[0].id;
if (!vortragPageId) throw new Error('Confluence-Seite "Vortraege" unter Dokumentenportal nicht gefunden');

function sanitizeFilename(thema, datum, url) {
  var ext = '';
  var urlPath = (url || '').split('?')[0];
  var lastDot = urlPath.lastIndexOf('.');
  if (lastDot !== -1 && lastDot > urlPath.length - 10) ext = urlPath.substring(lastDot).toLowerCase();
  if (!ext) ext = '.pdf';
  var today = new Date().toISOString().substring(0, 10);
  var datePrefix = datum ? datum.split('.').reverse().join('-') : today;
  var sanitized = (thema || 'Vortrag')
    .replace(/ä/g, 'ae').replace(/ö/g, 'oe').replace(/ü/g, 'ue')
    .replace(/Ä/g, 'Ae').replace(/Ö/g, 'Oe').replace(/Ü/g, 'Ue')
    .replace(/ß/g, 'ss')
    .replace(/[^a-zA-Z0-9]+/g, '-')
    .replace(/-+/g, '-').replace(/^-|-$/g, '')
    .substring(0, 60);
  return datePrefix + '_' + sanitized + ext;
}

var spaceKey = $('Code: Filtern & Transformieren').first().json.spaceKey || '';
return themen.map(function(t, idx) {
  var hasUrl = !!(t.vortragUrl && t.vortragUrl.trim());
  return { json: {
    thema: t.thema, datum: t.datum, vortragender: t.vortragender,
    vortragUrl: t.vortragUrl || '', needsUpload: hasUrl,
    filename: hasUrl ? sanitizeFilename(t.thema, t.datum, t.vortragUrl) : '',
    vortragPageId: vortragPageId, themenIndex: idx, confluenceFileUrl: '',
    spaceKey: spaceKey
  }};
});

const item = $input.item;
const filename = item.json.filename || 'vortrag.pdf';
const newItem = { json: item.json, binary: {} };
if (item.binary && item.binary.pdf_binary) {
  newItem.binary.pdf_binary = {
    ...item.binary.pdf_binary,
    fileName: filename,
    mimeType: item.binary.pdf_binary.mimeType || 'application/octet-stream'
  };
}
return [newItem];

const input = $input.item.json;

// TRUE-Pfad: Anhang existierte bereits → _existing_url ist gesetzt
// FALSE-Pfad: Neuer Upload → POST-Response mit results[0]._links.download
var confluenceFileUrl = '';
var themenIndex, thema, datum, vortragender, vortragUrl, summary, spaceKey;

if (input._existing_url !== undefined) {
  // TRUE-Pfad: alle Originaldaten direkt im Item vorhanden
  confluenceFileUrl = input._existing_url;
  themenIndex = input.themenIndex;
  thema = input.thema;
  datum = input.datum;
  vortragender = input.vortragender;
  vortragUrl = input.vortragUrl;
  summary = input.summary || '';
  spaceKey = input.spaceKey || '';
} else {
  // FALSE-Pfad: POST-Response, Originaldaten via Cross-Node-Referenz
  const results = input.results || [];
  const base = 'https://blboardsolutions.atlassian.net/wiki';
  if (results.length > 0 && results[0]._links) {
    confluenceFileUrl = results[0]._links.download
      ? base + results[0]._links.download
      : '';
  }
  const orig = $('Code: Uploads vorbereiten').item.json;
  themenIndex = orig.themenIndex;
  thema = orig.thema;
  datum = orig.datum;
  vortragender = orig.vortragender;
  vortragUrl = orig.vortragUrl;
  summary = orig.summary || '';
  spaceKey = orig.spaceKey || '';
}

return [{ json: {
  thema, datum, vortragender, vortragUrl, summary, spaceKey,
  themenIndex, needsUpload: true,
  confluenceFileUrl
} }];

const items = $input.all();
const originalThemen = $('Code: Filtern & Transformieren').first().json.themen || [];

// spaceKey aus den Input-Items holen (direkt weitergereicht aus Uploads vorbereiten)
var spaceKey = '';
for (var i = 0; i < items.length; i++) {
  if (items[i].json.spaceKey) { spaceKey = items[i].json.spaceKey; break; }
}
// Fallback: Cross-Node-Referenz
if (!spaceKey) {
  try { spaceKey = $('Code: Filtern & Transformieren').first().json.spaceKey || ''; } catch(e) {}
}

const uploadMap = {};
items.forEach(function(item) {
  if (item.json.confluenceFileUrl) uploadMap[item.json.themenIndex] = item.json.confluenceFileUrl;
});

const updatedThemen = originalThemen.map(function(t, idx) {
  return { thema: t.thema, datum: t.datum, vortragender: t.vortragender,
           vortragUrl: t.vortragUrl || '', summary: t.summary || '',
           confluenceFileUrl: uploadMap[idx] || '' };
});

return [{ json: { themen: updatedThemen, count: updatedThemen.length, spaceKey: spaceKey } }];

// HTTP: Confluence Anhang prüfen ersetzt das Item-JSON.
// Originaldaten aus Code: Uploads vorbereiten holen.
const origData = $('Code: Uploads vorbereiten').item.json;
const shareUrl = origData.vortragUrl || '';
const encoded = 'u!' + Buffer.from(shareUrl).toString('base64')
  .replace(/=+$/, '').replace(/\//g, '_').replace(/\+/g, '-');
return {
  json: {
    ...origData,
    graph_download_url: `https://graph.microsoft.com/v1.0/shares/${encoded}/driveItem/content`
  }
};

// Prüfen-Response mit Originaldaten aus Code: Uploads vorbereiten zusammenführen
// So sind themenIndex und andere Felder nach dem IF-Node noch verfügbar
const prüfenRes = $input.item.json;
const orig = $('Code: Uploads vorbereiten').item.json;

const prüfenResults = prüfenRes.results || [];
const base = 'https://blboardsolutions.atlassian.net/wiki';
var existingUrl = '';
if (prüfenResults.length > 0 && prüfenResults[0]._links) {
  existingUrl = prüfenResults[0]._links.download
    ? base + prüfenResults[0]._links.download
    : '';
}

return { json: {
  // Originaldaten
  thema: orig.thema,
  datum: orig.datum,
  vortragender: orig.vortragender,
  vortragUrl: orig.vortragUrl,
  summary: orig.summary || '',
  themenIndex: orig.themenIndex,
  vortragPageId: orig.vortragPageId,
  filename: orig.filename,
  needsUpload: orig.needsUpload,
  spaceKey: orig.spaceKey || '',
  // Prüfen-Ergebnis
  _attachment_found: prüfenResults.length > 0,
  _existing_url: existingUrl
} };
